  seed: SEED,
  modelId: MODEL_ID,
  provider: new MockDirectorProvider({ latencyMs: 0 }),
  gate2: passingGate2(validShallowsManifestFixture),
  artifacts: { fs, rootDir: ROOT_DIR },
  now: () => CREATED_AT,
});

export const getTransportHandlers = (): TransportHandlers => handlers;

